    AND `created_time`  <=  #{vo.endTime}



    AND DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(created_time/1000),
    @@session.time_zone,#{vo.timeZoneDb}),'%Y-%m-%d') = CURDATE()

SELECT site_code as siteCode ,site_name as siteName,COUNT(channel_id) as sendCount from channel_sending_statistic
WHERE 1=1
AND `site_code` LIKE CONCAT('%', #{vo.siteCode}, '%')
AND `site_name` LIKE CONCAT('%', #{vo.siteName}, '%')
AND `channel_name` LIKE CONCAT('%', #{vo.channelName}, '%')
AND `channel_code` LIKE CONCAT('%', #{vo.channelCode}, '%')
AND `channel_id` IN
#{id}
AND `channel_type` = #{vo.channelType}
AND `created_time` >= #{vo.startTime}
AND `created_time` <= #{vo.endTime}
AND DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(created_time/1000), @@session.time_zone,#{vo.timeZoneDb}),'%Y-%m-%d') = CURDATE()
GROUP BY site_code,site_name ORDER BY site_code,site_name

