SELECT channel_name as channelName ,channel_code as channelCode,channel_id as channelId ,COUNT(channel_id) as sendCount,host
from channel_sending_statistic

WHERE  1=1

    AND `site_code` = #{vo.siteCode}


    AND `channel_name` LIKE CONCAT('%', #{vo.channelName}, '%')


    AND `channel_code` LIKE CONCAT('%', #{vo.channelCode}, '%')


    AND `channel_type` = #{vo.channelType}


    AND `created_time`  >=  #{vo.startTime}


    AND `created_time`  <=  #{vo.endTime}



    AND DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(created_time/1000),
    @@session.time_zone,#{vo.timeZoneDb}),'%Y-%m-%d') = CURDATE()


GROUP BY channel_id,channel_name,channel_code ,host ORDER BY channel_id,channel_name,channel_code
